class Solution {
    /**
     * Given a binary string s, we can perform at most one swap of any two characters in s.
     * After the swap, we select a balanced substring from s.
     * A string is balanced if the number of '0's equals the number of '1's.
     * Return the maximum length of a balanced substring we can select.
     *
     * @param s The input binary string.
     * @return The maximum length of a balanced substring.
     */
    public static long solve(String s) {
        int n = s.length();
        int maxLen = 0;

        // Helper function to find the maximum length of a balanced substring in a given string t
        // This is a standard prefix sum/hashmap problem.
        java.util.function.Function<String, Integer> maxBalancedSubstring = (t) -> {
            if (t.isEmpty()) return 0;
            int currentBalance = 0; // count('1') - count('0')
            // Map stores: balance -> first index where this balance was achieved
            java.util.Map<Integer, Integer> firstOccurrence = new java.util.HashMap<>();
            firstOccurrence.put(0, -1); // Balance 0 is achieved before index 0

            int currentMax = 0;
            for (int i = 0; i < t.length(); i++) {
                if (t.charAt(i) == '1') {
                    currentBalance++;
                } else { // t.charAt(i) == '0'
                    currentBalance--;
                }

                if (firstOccurrence.containsKey(currentBalance)) {
                    // A subarray from firstOccurrence.get(currentBalance) + 1 to i is balanced
                    int length = i - firstOccurrence.get(currentBalance);
                    currentMax = Math.max(currentMax, length);
                } else {
                    // Record the first time we see this balance
                    firstOccurrence.put(currentBalance, i);
                }
            }
            return currentMax;
        };

        // 1. Case: No swap
        maxLen = Math.max(maxLen, maxBalancedSubstring.apply(s));

        // 2. Case: Perform one swap (s[i] <-> s[j])
        char[] chars = s.toCharArray();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                // Only perform a swap if it potentially changes the string and might help.
                // If chars[i] == chars[j], the swap does nothing, already covered by Case 1.
                if (chars[i] == chars[j]) continue;

                // Perform the swap virtually
                char temp = chars[i];
                chars[i] = chars[j];
                chars[j] = temp;
                String swappedS = new String(chars);

                // Check the resulting string
                maxLen = Math.max(maxLen, maxBalancedSubstring.apply(swappedS));

                // Undo the swap (backtrack)
                temp = chars[i];
                chars[i] = chars[j];
                chars[j] = temp;
            }
        }

        return maxLen;
    }
}
