import java.util.Arrays;

public class Solution {
    /**
     * Calculates the maximum length of a balanced substring achievable after at most one swap.
     * A balanced string has an equal number of '0's and '1's.
     * 
     * @param s The input binary string.
     * @return The maximum length of a balanced substring.
     */
    public static long solve(String s) {
        int n = s.length();
        long maxLen = 0;

        // Case 0: No swap (original string)
        // Find the maximum balanced substring in the original string s
        for (int len = 2; len <= n; len += 2) {
            for (int i = 0; i <= n - len; i++) {
                String sub = s.substring(i, i + len);
                int count0 = 0;
                int count1 = 0;
                for (char c : sub.toCharArray()) {
                    if (c == '0') count0++;
                    else count1++;
                }
                if (count0 == count1) {
                    maxLen = Math.max(maxLen, len);
                }
            }
        }

        // Case 1: One swap
        // Iterate over all possible pairs of indices (i, j) to swap
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                char[] arr = s.toCharArray();
                // Perform the swap
                char temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
                String sSwapped = new String(arr);

                // Find the maximum balanced substring in the swapped string sSwapped
                for (int len = 2; len <= n; len += 2) {
                    for (int start = 0; start <= n - len; start++) {
                        String sub = sSwapped.substring(start, start + len);
                        int count0 = 0;
                        int count1 = 0;
                        for (char c : sub.toCharArray()) {
                            if (c == '0') count0++;
                            else count1++;
                        }
                        if (count0 == count1) {
                            maxLen = Math.max(maxLen, len);
                        }
                    }
                }
            }
        }

        // The empty string is balanced with length 0, so maxLen starts at 0 or is at least 0.
        return maxLen;
    }
}
